import logging
import json
from pathlib import Path
from typing import Dict, Optional, Any, Tuple
import pandas as pd
import numpy as np
from sklearn.ensemble import RandomForestRegressor
from sklearn.model_selection import GridSearchCV, cross_val_score
from sklearn.metrics import r2_score, mean_absolute_error
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler
from src.utils.logging_config import setup_logging

logger = logging.getLogger(__name__)

def load_features_data(input_path: Path) -> pd.DataFrame:
    """Load the features dataset generated by the feature engineering pipeline."""
    if not input_path.exists():
        raise FileNotFoundError(f"Features file not found: {input_path}")
    df = pd.read_csv(input_path)
    logger.info(f"Loaded {len(df)} rows from {input_path}")
    return df

def prepare_data(df: pd.DataFrame, target_col: str = 'coercivity_Oe') -> Tuple[np.ndarray, np.ndarray, list]:
    """
    Prepare features (X) and target (y) for modeling.
    Excludes non-numeric columns and the target column.
    """
    # Identify feature columns (numeric, excluding target)
    feature_cols = [col for col in df.columns if df[col].dtype in ['int64', 'float64'] and col != target_col]
    
    if not feature_cols:
        raise ValueError("No numeric feature columns found in the dataset.")
    
    X = df[feature_cols].values
    y = df[target_col].values
    
    logger.info(f"Prepared data: X shape {X.shape}, y shape {y.shape}")
    logger.info(f"Using features: {feature_cols}")
    
    return X, y, feature_cols

def create_model_pipeline() -> Pipeline:
    """Create a pipeline with StandardScaler and RandomForestRegressor."""
    return Pipeline([
        ('scaler', StandardScaler()),
        ('regressor', RandomForestRegressor(random_state=42, n_jobs=-1))
    ])

def tune_hyperparameters(X: np.ndarray, y: np.ndarray, feature_names: list) -> Tuple[Any, Dict[str, Any]]:
    """
    Perform GridSearchCV to find the best hyperparameters for Random Forest.
    Uses a reduced grid for CPU efficiency as per project constraints.
    """
    param_grid = {
        'regressor__n_estimators': [50, 100],
        'regressor__max_depth': [None, 10, 20],
        'regressor__min_samples_split': [2, 5],
        'regressor__min_samples_leaf': [1, 2]
    }

    pipeline = create_model_pipeline()
    
    logger.info("Starting GridSearchCV for Random Forest hyperparameter tuning...")
    
    # Use 3-fold CV to reduce runtime on CPU-only CI
    grid_search = GridSearchCV(
        pipeline, 
        param_grid, 
        cv=3, 
        scoring='r2', 
        n_jobs=-1,
        verbose=1
    )
    
    grid_search.fit(X, y)
    
    best_params = grid_search.best_params_
    best_model = grid_search.best_estimator_
    
    logger.info(f"Best parameters: {best_params}")
    logger.info(f"Best CV R2 score: {grid_search.best_score_:.4f}")
    
    return best_model, best_params

def evaluate_model(model: Any, X: np.ndarray, y: np.ndarray) -> Dict[str, float]:
    """Evaluate the model using R2 and MAE."""
    y_pred = model.predict(X)
    
    r2 = r2_score(y, y_pred)
    mae = mean_absolute_error(y, y_pred)
    
    metrics = {
        'r2': float(r2),
        'mae': float(mae)
    }
    
    logger.info(f"Model Evaluation - R2: {r2:.4f}, MAE: {mae:.4f}")
    
    return metrics

def save_model(model: Any, output_path: Path) -> None:
    """Save the trained model using joblib."""
    import joblib
    output_path.parent.mkdir(parents=True, exist_ok=True)
    joblib.dump(model, output_path)
    logger.info(f"Model saved to {output_path}")

def save_metrics(metrics: Dict[str, float], best_params: Dict[str, Any], output_path: Path) -> None:
    """Save model metrics and best parameters to JSON."""
    output_path.parent.mkdir(parents=True, exist_ok=True)
    
    result = {
        'model_type': 'RandomForestRegressor',
        'metrics': metrics,
        'best_hyperparameters': best_params
    }
    
    with open(output_path, 'w') as f:
        json.dump(result, f, indent=2)
    logger.info(f"Metrics saved to {output_path}")

def run_random_forest_regression(
    input_path: Path,
    model_output_dir: Path,
    metrics_output_path: Path,
    target_col: str = 'coercivity_Oe'
) -> Tuple[Any, Dict[str, float], Dict[str, Any]]:
    """
    Main function to run the Random Forest regression pipeline.
    1. Load features data
    2. Prepare X, y
    3. Tune hyperparameters
    4. Evaluate
    5. Save model and metrics
    """
    logger.info("Starting Random Forest Regression Pipeline...")
    
    # Load data
    df = load_features_data(input_path)
    
    # Prepare data
    X, y, feature_names = prepare_data(df, target_col)
    
    # Tune hyperparameters
    best_model, best_params = tune_hyperparameters(X, y, feature_names)
    
    # Evaluate
    metrics = evaluate_model(best_model, X, y)
    
    # Save outputs
    model_path = model_output_dir / 'random_forest_model.joblib'
    save_model(best_model, model_path)
    
    save_metrics(metrics, best_params, metrics_output_path)
    
    logger.info("Random Forest Regression Pipeline completed successfully.")
    
    return best_model, metrics, best_params

def main():
    """Entry point for the script."""
    setup_logging()
    
    # Define paths relative to project root
    project_root = Path(__file__).resolve().parent.parent.parent.parent
    input_path = project_root / 'data' / 'processed' / 'alloys_features.csv'
    model_output_dir = project_root / 'code' / 'models'
    metrics_output_path = project_root / 'data' / 'processed' / 'rf_model_metrics.json'
    
    try:
        run_random_forest_regression(input_path, model_output_dir, metrics_output_path)
    except Exception as e:
        logger.error(f"Pipeline failed: {e}", exc_info=True)
        raise

if __name__ == '__main__':
    main()
